import React, { useEffect, useMemo, useRef, useState } from "react";
import MainLayout from "../../layouts/MainLayout";
import ApiService from "../../services/ApiService";

function formatRoleLabel(role) {
  if (!role) {
    return "Dang cap nhat";
  }

  return role
    .toLowerCase()
    .split("_")
    .map((segment) => segment.charAt(0).toUpperCase() + segment.slice(1))
    .join(" ");
}

function formatDate(value) {
  if (!value) {
    return "Chua co thong tin";
  }

  const parsedDate = new Date(value);

  if (Number.isNaN(parsedDate.getTime())) {
    return "Chua co thong tin";
  }

  return parsedDate.toLocaleDateString();
}

const ProfilePage = () => {
  const [user, setUser] = useState(null);
  const [message, setMessage] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const timeoutRef = useRef(null);

  useEffect(() => {
    const fetchUserInfo = async () => {
      try {
        const userInfo = await ApiService.getLoggedInUserInfo();
        setUser(userInfo?.user || null);
      } catch (error) {
        showMessage(
          error.response?.data?.message ||
            "Unable to load your profile right now."
        );
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserInfo();

    return () => {
      if (timeoutRef.current) {
        window.clearTimeout(timeoutRef.current);
      }
    };
  }, []);

  const showMessage = (msg) => {
    setMessage(msg);

    if (timeoutRef.current) {
      window.clearTimeout(timeoutRef.current);
    }

    timeoutRef.current = window.setTimeout(() => {
      setMessage("");
    }, 4000);
  };

  const profileFacts = useMemo(
    () => [
      { label: "Ho ten", value: user?.name || "Chua cap nhat" },
      { label: "Email", value: user?.email || "Chua cap nhat" },
      { label: "So dien thoai", value: user?.phoneNumber || "Chua cap nhat" },
      { label: "Vai tro", value: formatRoleLabel(user?.role) },
    ],
    [user]
  );

  return (
    <MainLayout>
      {message && <div className="message">{message}</div>}

      <div className="profile-dashboard">
        {isLoading && (
          <div className="profile-shell">
            <div className="profile-panel">
              <h1>Dang tai ho so...</h1>
              <p>He thong dang nap thong tin tai khoan cua ban.</p>
            </div>
          </div>
        )}

        {!isLoading && user && (
          <div className="profile-shell">
            <section className="profile-hero">
              <div className="profile-hero-copy">
                <span className="profile-eyebrow">Profile Dashboard</span>
                <h1>{user.name}</h1>
                <p>
                  Khu vuc nay tong hop thong tin tai khoan, vai tro dang su dung
                  va trang thai truy cap hien tai cua ban trong he thong kho.
                </p>
              </div>

              <div className="profile-avatar-badge">
                {(user.name || "U").trim().charAt(0).toUpperCase()}
              </div>
            </section>

            <div className="profile-grid">
              <article className="profile-panel">
                <div className="profile-panel-heading">
                  <div>
                    <span className="profile-section-label">Tai Khoan</span>
                    <h2>Thong tin ca nhan</h2>
                  </div>
                </div>

                <div className="profile-info-list">
                  {profileFacts.map((item) => (
                    <div className="profile-item" key={item.label}>
                      <label>{item.label}</label>
                      <span>{item.value}</span>
                    </div>
                  ))}
                </div>
              </article>

              <article className="profile-panel profile-panel-accent">
                <div className="profile-panel-heading">
                  <div>
                    <span className="profile-section-label">Tong Quan</span>
                    <h2>Trang thai su dung</h2>
                  </div>
                </div>

                <div className="profile-stat-grid">
                  <div className="profile-stat-card">
                    <span>Trang thai</span>
                    <strong>
                      {user.active === false ? "Da vo hieu hoa" : "Dang hoat dong"}
                    </strong>
                    <p>Quyen truy cap hien tai cua tai khoan nay.</p>
                  </div>

                  <div className="profile-stat-card">
                    <span>Ngay tao</span>
                    <strong>{formatDate(user.createdAt)}</strong>
                    <p>Thoi diem tai khoan duoc them vao he thong.</p>
                  </div>

                  <div className="profile-stat-card">
                    <span>Vai tro hien tai</span>
                    <strong>{formatRoleLabel(user.role)}</strong>
                    <p>Vai tro xac dinh khu vuc va tac vu duoc truy cap.</p>
                  </div>
                </div>
              </article>
            </div>
          </div>
        )}

        {!isLoading && !user && (
          <div className="profile-shell">
            <div className="profile-panel">
              <h1>Khong tim thay ho so</h1>
              <p>He thong chua tra ve du lieu tai khoan cho phien dang nhap nay.</p>
            </div>
          </div>
        )}
      </div>
    </MainLayout>
  );
};

export default ProfilePage;
